preToolUse.bash:
python3 -c '
import json, os, re, sys
from pathlib import Path

def append_jsonl(path: Path, obj):
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("a", encoding="utf-8") as f:
        f.write(json.dumps(obj, ensure_ascii=False) + "\n")

def load_json(path: Path, default):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default

data = json.load(sys.stdin)
cwd = Path(data.get("cwd") or os.getcwd())
base = cwd / ".copilot-mission-control"
append_jsonl(base / "global" / "hook-events.jsonl", {"source": "hook", "event": "preToolUse", "payload": data})
active_path = base / "state" / "active-run-id"
run_id = active_path.read_text(encoding="utf-8").strip() if active_path.exists() else ""
if not run_id:
    raise SystemExit(0)
append_jsonl(base / "runs" / run_id / "journal.jsonl", {"ts": data.get("timestamp"), "source": "hook", "event": "preToolUse", "payload": data})
policy = load_json(base / "runs" / run_id / "policy.json", {"allowCommit": False, "allowPush": False, "allowPR": False})
args = data.get("toolArgs")
if isinstance(args, str):
    try:
        args = json.loads(args)
    except Exception:
        args = {"raw": args}
cmd = ""
if isinstance(args, dict):
    cmd = args.get("command") or args.get("script") or args.get("bash") or ""
lowered = cmd.lower()
tool = (data.get("toolName") or "").lower()
deny = None
always_deny = [r"(^|\s)sudo\b", r"rm\s+-rf\s+/", r"\bmkfs\b", r"\bdd\s+if=", r"diskutil\s+erase", r"\bshutdown\b", r"\breboot\b", r":\(\)\s*\{\s*:\|:&\s*\};:"]
if tool in {"bash", "powershell"} and any(re.search(p, lowered) for p in always_deny):
    deny = "Blocked by copilot-mission-control: dangerous system command."
elif tool in {"bash", "powershell"}:
    if not policy.get("allowCommit", False) and re.search(r"\bgit\s+commit\b", lowered):
        deny = "Blocked by copilot-mission-control: git commit is disabled for this run."
    elif not policy.get("allowPush", False) and (re.search(r"\bgit\s+push\b", lowered) or re.search(r"\bgit\s+tag\b", lowered)):
        deny = "Blocked by copilot-mission-control: git push/tag is disabled for this run."
    elif not policy.get("allowPR", False) and (re.search(r"\bgh\s+pr\s+(create|merge)\b", lowered) or re.search(r"\bhub\s+pull-request\b", lowered)):
        deny = "Blocked by copilot-mission-control: PR creation/merge is disabled for this run."
if deny:
    print(json.dumps({"permissionDecision": "deny", "permissionDecisionReason": deny}, ensure_ascii=False))
'

preToolUse.powershell:
$inputJson = [Console]::In.ReadToEnd()
$data = $inputJson | ConvertFrom-Json
$cwd = if ($data.cwd) { $data.cwd } else { (Get-Location).Path }
$base = Join-Path $cwd '.copilot-mission-control'
$globalDir = Join-Path $base 'global'
New-Item -ItemType Directory -Force -Path $globalDir | Out-Null
$globalFile = Join-Path $globalDir 'hook-events.jsonl'
$globalRecord = @{ source = 'hook'; event = 'preToolUse'; payload = $data } | ConvertTo-Json -Compress -Depth 20
Add-Content -Path $globalFile -Value $globalRecord
$activePath = Join-Path (Join-Path $base 'state') 'active-run-id'
if (-not (Test-Path $activePath)) { exit 0 }
$runId = (Get-Content $activePath -Raw).Trim()
if (-not $runId) { exit 0 }
$runDir = Join-Path (Join-Path $base 'runs') $runId
New-Item -ItemType Directory -Force -Path $runDir | Out-Null
$journalFile = Join-Path $runDir 'journal.jsonl'
$journalRecord = @{ ts = $data.timestamp; source = 'hook'; event = 'preToolUse'; payload = $data } | ConvertTo-Json -Compress -Depth 20
Add-Content -Path $journalFile -Value $journalRecord
$policyPath = Join-Path $runDir 'policy.json'
$policy = @{ allowCommit = $false; allowPush = $false; allowPR = $false }
if (Test-Path $policyPath) {
  try { $policy = Get-Content $policyPath -Raw | ConvertFrom-Json } catch { }
}
$tool = (($data.toolName | Out-String).Trim()).ToLowerInvariant()
$toolArgsRaw = $data.toolArgs
$cmd = ''
if ($toolArgsRaw) {
  try {
    $toolArgs = $toolArgsRaw | ConvertFrom-Json
    if ($toolArgs.command) { $cmd = $toolArgs.command }
    elseif ($toolArgs.script) { $cmd = $toolArgs.script }
    elseif ($toolArgs.bash) { $cmd = $toolArgs.bash }
  } catch {
    $cmd = [string]$toolArgsRaw
  }
}
$lowered = $cmd.ToLowerInvariant()
$deny = $null
if ($tool -eq 'bash' -or $tool -eq 'powershell') {
  if ($lowered -match '(^|\s)sudo ' -or $lowered -match 'rm\s+-rf\s+/' -or $lowered -match ' mkfs ' -or $lowered -match ' dd\s+if=' -or $lowered -match 'diskutil\s+erase' -or $lowered -match ' shutdown ' -or $lowered -match ' reboot ') {
    $deny = 'Blocked by copilot-mission-control: dangerous system command.'
  } elseif (-not $policy.allowCommit -and $lowered -match ' git\s+commit ') {
    $deny = 'Blocked by copilot-mission-control: git commit is disabled for this run.'
  } elseif (-not $policy.allowPush -and ($lowered -match ' git\s+push ' -or $lowered -match ' git\s+tag ')) {
    $deny = 'Blocked by copilot-mission-control: git push/tag is disabled for this run.'
  } elseif (-not $policy.allowPR -and ($lowered -match ' gh\s+pr\s+(create|merge) ' -or $lowered -match ' hub\s+pull-request ')) {
    $deny = 'Blocked by copilot-mission-control: PR creation/merge is disabled for this run.'
  }
}
if ($deny) {
  @{ permissionDecision = 'deny'; permissionDecisionReason = $deny } | ConvertTo-Json -Compress
}
